import axios from 'axios';

const BASE_URL = 'http://localhost:8080/api/fine';
const memberFinesInflight = new Map();

async function requestWithFallback(requests) {
  let lastError;
  for (const request of requests) {
    try {
      const response = await request();
      return response.data;
    } catch (err) {
      if (err?.response?.status === 401 || err?.response?.status === 403) {
        throw err;
      }
      lastError = err;
    }
  }
  throw lastError;
}

export const fineService = {
  getAll: () => axios.get(BASE_URL).then(r => r.data),
  getByMember: (memberId) => {
    const key = String(memberId);
    if (memberFinesInflight.has(key)) {
      return memberFinesInflight.get(key);
    }
    const request = requestWithFallback([
      () => axios.get(`${BASE_URL}/member/${memberId}`),
      () => axios.get(`${BASE_URL}/members/${memberId}`),
      () => axios.get(`${BASE_URL}/${memberId}`),
    ]).finally(() => {
      memberFinesInflight.delete(key);
    });
    memberFinesInflight.set(key, request);
    return request;
  },
  calculateFine: (requestId, returnDate) => axios.post(`${BASE_URL}/${requestId}/${returnDate}`).then(r => r.data),
  payFine: (id) => requestWithFallback([
    () => axios.put(`${BASE_URL}/${id}/pay`, {}),
    () => axios.patch(`${BASE_URL}/${id}/pay`),
    () => axios.post(`${BASE_URL}/${id}/pay`, {}),
    () => axios.put(`${BASE_URL}/pay/${id}`, {}),
    () => axios.patch(`${BASE_URL}/pay/${id}`),
    () => axios.post(`${BASE_URL}/pay/${id}`, {}),
    () => axios.put(`${BASE_URL}/${id}/status/PAID`, {}),
    () => axios.patch(`${BASE_URL}/${id}/status/PAID`),
  ]),
  deleteFine: (id) => axios.delete(`${BASE_URL}/${id}`).then(r => r.data),
};
